import graphene
from flask import Flask
from flask_graphql import GraphQLView

class Product(graphene.ObjectType):
    id = graphene.ID()
    name = graphene.String()
    description = graphene.String()
    price = graphene.Float()
    category_id = graphene.ID()

class Category(graphene.ObjectType):
    id = graphene.ID()
    name = graphene.String()
    products = graphene.List(Product)

class Review(graphene.ObjectType):
    id = graphene.ID()
    product_id = graphene.ID()
    user = graphene.String()
    rating = graphene.Int()
    comment = graphene.String()

class Query(graphene.ObjectType):
    products = graphene.List(Product)
    categories = graphene.List(Category)
    reviews = graphene.List(Review)

    def resolve_products(self, info):
        # Replace with actual data retrieval logic
        return [
            Product(id="1", name="Product 1", description="Description 1", price=10.99, category_id="1"),
            Product(id="2", name="Product 2", description="Description 2", price=15.99, category_id="2")
        ]

    def resolve_categories(self, info):
        # Replace with actual data retrieval logic
        return [
            Category(id="1", name="Category 1"),
            Category(id="2", name="Category 2")
        ]

    def resolve_reviews(self, info):
        # Replace with actual data retrieval logic
        return [
            Review(id="1", product_id="1", user="User A", rating=5, comment="Great product!"),
            Review(id="2", product_id="2", user="User B", rating=4, comment="Good value for money.")
        ]

schema = graphene.Schema(query=Query)

app = Flask(__name__)
app.add_url_rule('/graphql', view_func=GraphQLView.as_view('graphql', schema=schema, graphiql=True))

if __name__ == '__main__':
    app.run(debug=True)